#!/usr/bin/env node
// Outputs a JSON matrix of { id, skipAutogenerated } entries for every
// feature that has both a devcontainer-feature.json and a test/test.sh file.
// Used by the "Discover features" step in test.yml.
import { existsSync, readFileSync, readdirSync } from "node:fs";
import { join, resolve } from "node:path";

const srcRoot = resolve("src");
const testRoot = resolve("test");

if (!existsSync(srcRoot)) {
	process.stdout.write("[]");
	process.exit(0);
}

const entries = readdirSync(srcRoot)
	.filter((f) => {
		const featureJson = join(srcRoot, f, "devcontainer-feature.json");
		const testSh = join(testRoot, f, "test.sh");
		return existsSync(featureJson) && existsSync(testSh);
	})
	.map((id) => {
		const featureJson = JSON.parse(readFileSync(join(srcRoot, id, "devcontainer-feature.json"), "utf8"));
		const installsAfter = featureJson.installsAfter || [];
		// Skip auto-generated test for features that depend on another local
		// savvy-web feature (e.g. package-manager requires node).
		const skipAutogenerated = installsAfter.some((dep) => dep.includes("ghcr.io/savvy-web/"));
		return { id, skipAutogenerated };
	});

process.stdout.write(JSON.stringify(entries));
